// Procesa el CSV de Google Sheets con las tasas oficiales.
// Tolerante a errores: si algo falla, devuelve lista vacia marcada con error
// para que el AI Agent pueda responder un mensaje de respaldo amable.

try {
  const respuesta = $('Consultar Tasas').first().json;
  const csv = (respuesta && respuesta.data) ? String(respuesta.data) : '';

  if (!csv) {
    return { lista: [], error: 'No se recibieron datos del CSV de tasas' };
  }

  const lineas = csv.split(/\r?\n/).filter(l => l.trim() !== '');
  const resultados = [];

  // Saltamos la fila 0 (encabezado: Pais, tE, mE, tR, mR)
  for (let i = 1; i < lineas.length; i++) {
    const col = lineas[i].split(',');
    if (col.length < 5) continue;

    const pais = (col[0] || '').trim();
    const tE = parseFloat(col[1]) || 0;
    const mE = parseFloat(col[2]) || 0;
    const tR = parseFloat(col[3]) || 0;
    const mR = parseFloat(col[4]) || 0;

    if (!pais || (tE === 0 && tR === 0)) continue;

    resultados.push({
      Pais: pais,
      Envio: (tE * (1 - mE / 100)).toFixed(2),
      Recibo: (tR * (1 + mR / 100)).toFixed(2)
    });
  }

  return {
    lista: resultados,
    error: resultados.length === 0 ? 'Lista vacia despues de procesar' : null
  };
} catch (err) {
  return { lista: [], error: 'Error procesando CSV: ' + err.message };
}
